import math

def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0
    max_n = n - 1
    is_prime = [True] * (max_n + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(math.isqrt(max_n)) + 1):
        if is_prime[i]:
            for j in range(i * i, max_n + 1, i):
                is_prime[j] = False
    sumA = 0
    sumB = 0
    for i in range(n):
        if is_prime[i]:
            sumA += nums[i]
        else:
            sumB += nums[i]
    return abs(sumA - sumB)
